PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?country WHERE {
  ?country wdt:P31 wd:Q6256 .
  ?country wdt:P30 wd:Q46 .
  FILTER(?country != wd:Q142)
  .
  FILTER NOT EXISTS {
    ?war wdt:P26 ?country .
    ?war wdt:P26 wd:Q142 .
  }
}
